package ir.tahamohamadi.resume.api.admin;
import ir.tahamohamadi.common.api.PageResponse; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.*; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import java.util.UUID;
@RestController @Validated @RequestMapping("/api/v1/admin/resume/documents") public class AdminResumeDocumentController {private final AdminResumeDocumentService service;public AdminResumeDocumentController(AdminResumeDocumentService service){this.service=service;}@GetMapping public PageResponse<AdminResumeDocumentResponse> list(@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size){return PageResponse.from(service.list(page,size));}@GetMapping("/{id}") public AdminResumeDocumentResponse get(@PathVariable UUID id){return service.get(id);}@PostMapping public ResponseEntity<AdminResumeDocumentResponse> create(@Valid @RequestBody AdminResumeDocumentRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}@PutMapping("/{id}") public AdminResumeDocumentResponse update(@PathVariable UUID id,@Valid @RequestBody AdminResumeDocumentRequest r){return service.update(id,r);}@PostMapping("/{id}/publish") public AdminResumeDocumentResponse publish(@PathVariable UUID id,@RequestParam long version){return service.publish(id,version);}@PostMapping("/{id}/archive") public AdminResumeDocumentResponse archive(@PathVariable UUID id,@RequestParam long version){return service.archive(id,version);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id,@RequestParam long version){service.delete(id,version);}}
